// // This JK flip-flop toggles its output when both J and K inputs are low, sets it when J is low and K is high, resets it when J is high and K is low.
module top_module(
	input clk,
	input j,
	input k,
	output reg q);always @(posedge clk) begin
	if (j & ~k)
		q <= 1;
	else if (~j & k)
		q <= 0;
	else if (j & k)
		q <= ~q;
end

endmodule
